template<typename T, int NN>

struct bit {

  typedef std::function<T(T,T)> OP;

  T data_[NN], e_; // 0-base

  OP& op_;

  bit(OP& op, T e) : e_(e), op_(op) { std::fill_n(data_, NN, e_); }

  int lb(int i){ return i&-i; }

  T query(int i) { // 1-base

